"use strict";(globalThis.webpackChunkwayang_website=globalThis.webpackChunkwayang_website||[]).push([[4802],{5850(e,a,t){t.r(a),t.d(a,{assets:()=>l,contentTitle:()=>r,default:()=>d,frontMatter:()=>s,metadata:()=>o,toc:()=>c});var n=t(4848),i=t(8453);const s={slug:"spatial-wayang",title:"Bringing Spatial Data Processing to Apache Wayang",authors:["max.speer","anton.persitzky","felix.treykorn"],tags:["wayang","spatial"]},r="Bringing Spatial Data Processing to Apache Wayang",o={permalink:"/blog/spatial-wayang",source:"@site/blog/2026-05-19-spatial-wayang.md",title:"Bringing Spatial Data Processing to Apache Wayang",description:"Apache Wayang already enables a large variety of data processing workflows, ranging from basic data retrieval and filtering to complex ML tasks. However, there are additional areas that could benefit from its platform flexibility. As part of a university project, we implemented spatial operators in Apache Wayang. This enables the execution of workflows using geospatial data, including spatial join and filter operations. Since execution times can differ significantly depending on the chosen platform, spatial workflows can benefit greatly from Wayang\u2019s cross-platform capabilities.",date:"2026-05-19T00:00:00.000Z",formattedDate:"May 19, 2026",tags:[{label:"wayang",permalink:"/blog/tags/wayang"},{label:"spatial",permalink:"/blog/tags/spatial"}],readingTime:5.84,hasTruncateMarker:!1,authors:[{name:"Maximilian Speer",title:"HPI Student",url:"https://github.com/MaxSpeer",imageURL:"https://avatars.githubusercontent.com/u/82819900?s=96&v=4",key:"max.speer"},{name:"Anton Persitzky",title:"HPI Student",url:"https://github.com/instant-sky",imageURL:"https://avatars.githubusercontent.com/u/82519211?v=4",key:"anton.persitzky"},{name:"Felix Treykorn",title:"HPI Student",url:"https://github.com/treyfel",imageURL:"https://avatars.githubusercontent.com/u/58570309?v=4",key:"felix.treykorn"}],frontMatter:{slug:"spatial-wayang",title:"Bringing Spatial Data Processing to Apache Wayang",authors:["max.speer","anton.persitzky","felix.treykorn"],tags:["wayang","spatial"]},unlisted:!1,nextItem:{title:"Apache Wayang Graduation",permalink:"/blog/wayang-graduation"}},l={authorsImageUrls:[void 0,void 0,void 0]},c=[{value:"Implementation",id:"implementation",level:2},{value:"Why Spatial Is a Plugin, Not a Platform",id:"why-spatial-is-a-plugin-not-a-platform",level:2},{value:"Benchmarks",id:"benchmarks",level:2},{value:"Future Work",id:"future-work",level:2}];function p(e){const a={a:"a",code:"code",h2:"h2",hr:"hr",li:"li",p:"p",pre:"pre",strong:"strong",ul:"ul",...(0,i.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(a.p,{children:"Apache Wayang already enables a large variety of data processing workflows, ranging from basic data retrieval and filtering to complex ML tasks. However, there are additional areas that could benefit from its platform flexibility. As part of a university project, we implemented spatial operators in Apache Wayang. This enables the execution of workflows using geospatial data, including spatial join and filter operations. Since execution times can differ significantly depending on the chosen platform, spatial workflows can benefit greatly from Wayang\u2019s cross-platform capabilities."}),"\n",(0,n.jsx)(a.hr,{}),"\n",(0,n.jsx)(a.h2,{id:"implementation",children:"Implementation"}),"\n",(0,n.jsx)(a.p,{children:"Workflows including spatial operators are not the main task in Apache Wayang. Therefore, we chose to add spatial support as a plugin that can be enabled separately."}),"\n",(0,n.jsx)(a.p,{children:"The two new operators we added are SpatialFilter and SpatialJoin, since many spatial workflows primarily rely on these two operations."}),"\n",(0,n.jsx)(a.p,{children:"To support multiple data sources and geometry formats, we introduced an internal geometry representation, SpatialGeometry, that enables translation between formats. This allows geometries stored as WKT, WKB, and GeoJSON to be read and, if necessary, converted to the type expected by the consuming operator."}),"\n",(0,n.jsx)(a.p,{children:"For the execution of spatial jobs, we currently support Java, PostgreSQL, and Spark as backends. The Spark implementation uses Apache Sedona, a well-established library for distributed processing of spatial data. The Java implementation is based on JTS, and the PostgreSQL platform uses PostGIS for spatial operations."}),"\n",(0,n.jsx)(a.pre,{children:(0,n.jsx)(a.code,{className:"language-java",children:'WayangContext wayangContext = new WayangContext(configuration)\n                .withPlugin(Java.basicPlugin())\n                .withPlugin(Postgres.plugin())\n                .withPlugin(Spatial.plugin());\n\nfinal Collection<Long> outputcount = builder\n       .readTable(new PostgresTableSource(tableName, "ST_AsText(geom)"))\n       .spatialFilter(\n               (input -> WayangGeometry.fromStringInput(input.getString(0))),\n               SpatialPredicate.INTERSECTS,\n               queryGeometry\n       ).withSqlGeometryColumnName("geom")\n       .withTargetPlatform(Postgres.platform())\n       .count()\n       .collect();\n\nSystem.out.println("Spatial Filter Postgres Result Size: " + outputcount);\n'})}),"\n",(0,n.jsx)(a.hr,{}),"\n",(0,n.jsx)(a.h2,{id:"why-spatial-is-a-plugin-not-a-platform",children:"Why Spatial Is a Plugin, Not a Platform"}),"\n",(0,n.jsx)(a.p,{children:"In the current Wayang architecture, a platform is responsible for runtime ownership: it defines a Platform implementation, provides an executor factory, defines channel conversions, and integrates cost models. This can be seen clearly in modules such as Java (JavaPlatform + JavaExecutor) and PostgreSQL (PostgresPlatform via JdbcPlatformTemplate + JdbcExecutor)."}),"\n",(0,n.jsx)(a.p,{children:"The spatial extension is intentionally different. It does not introduce a new Platform subclass and does not provide its own executor. Instead, wayang-spatial is implemented as a plugin (Spatial.java) that contributes operators, mappings for those operators, and specifies required platforms."}),"\n",(0,n.jsxs)(a.p,{children:["The logical spatial operators (",(0,n.jsx)(a.code,{children:"SpatialFilterOperator"}),", ",(0,n.jsx)(a.code,{children:"SpatialJoinOperator"}),", ",(0,n.jsx)(a.code,{children:"GeoJsonFileSource"}),") still live in ",(0,n.jsx)(a.code,{children:"wayang-basic"})," and are included in the Java-Scala API. The spatial plugin extends the system by adding platform-specific execution operators and transformation rules that map Wayang operators to their platform implementations."]}),"\n",(0,n.jsxs)(a.p,{children:["At registration time, ",(0,n.jsx)(a.code,{children:"WayangContext.withPlugin(...)"})," calls ",(0,n.jsx)(a.code,{children:"plugin.configure(configuration)"}),". This whitelists the required platforms and spatial mappings. During optimization, mappings such as ",(0,n.jsx)(a.code,{children:"SpatialFilterMapping"})," and ",(0,n.jsx)(a.code,{children:"SpatialJoinMapping"})," rewrite logical operators into execution operators such as:"]}),"\n",(0,n.jsxs)(a.ul,{children:["\n",(0,n.jsxs)(a.li,{children:[(0,n.jsx)(a.code,{children:"JavaSpatialFilterOperator"})," / ",(0,n.jsx)(a.code,{children:"JavaSpatialJoinOperator"})]}),"\n",(0,n.jsxs)(a.li,{children:[(0,n.jsx)(a.code,{children:"SparkSpatialFilterOperator"})," / ",(0,n.jsx)(a.code,{children:"SparkSpatialJoinOperator"})]}),"\n",(0,n.jsxs)(a.li,{children:[(0,n.jsx)(a.code,{children:"PostgresSpatialFilterOperator"})," / ",(0,n.jsx)(a.code,{children:"PostgresSpatialJoinOperator"})]}),"\n"]}),"\n",(0,n.jsx)(a.p,{children:"Execution is then handled by the existing platform runtimes:"}),"\n",(0,n.jsxs)(a.ul,{children:["\n",(0,n.jsxs)(a.li,{children:["Java operators are executed by ",(0,n.jsx)(a.code,{children:"JavaExecutor"})]}),"\n",(0,n.jsxs)(a.li,{children:["Spark operators are executed by ",(0,n.jsx)(a.code,{children:"SparkExecutor"})]}),"\n",(0,n.jsxs)(a.li,{children:["PostgreSQL operators are executed through the JDBC runtime (",(0,n.jsx)(a.code,{children:"JdbcExecutor"}),")"]}),"\n"]}),"\n",(0,n.jsxs)(a.p,{children:["In practice, this is why applications have to register both a platform plugin (for general operators and channels) and a spatial plugin (for spatial mappings), for example ",(0,n.jsx)(a.code,{children:"Java.basicPlugin()"})," + ",(0,n.jsx)(a.code,{children:"Spatial.javaPlugin()"})," or ",(0,n.jsx)(a.code,{children:"Spark.basicPlugin()"})," + ",(0,n.jsx)(a.code,{children:"Spatial.sparkPlugin()"}),"."]}),"\n",(0,n.jsx)(a.p,{children:"This design provides three concrete advantages:"}),"\n",(0,n.jsxs)(a.ul,{children:["\n",(0,n.jsx)(a.li,{children:"No duplicate runtime stack, since executors, channels, and cost models remain centralized in the platforms"}),"\n",(0,n.jsx)(a.li,{children:"Clean multi-platform support for the same spatial semantics"}),"\n",(0,n.jsx)(a.li,{children:"Lower maintenance overhead, because spatial development efforts can focus on operator logic and mappings rather than recreating infrastructure"}),"\n"]}),"\n",(0,n.jsx)(a.p,{children:"Spatial support in Wayang is therefore best understood as a cross-platform capability extension: it contributes spatial semantics and translation, while execution remains fully owned by the underlying platforms."}),"\n",(0,n.jsx)("div",{style:{textAlign:"center"},children:(0,n.jsx)("img",{width:"90%",alt:"wayang-spatial architecture",src:"/img/architecture/wayang-spatial-architecture.png"})}),"\n",(0,n.jsx)(a.hr,{}),"\n",(0,n.jsx)(a.h2,{id:"benchmarks",children:"Benchmarks"}),"\n",(0,n.jsx)(a.p,{children:"Below we show scenarios where it is advantageous to be able to freely choose the execution depending on the use case. The following benchmarks are not intended to be exhaustive tests of our new operators but rather to highlight how using the platform independence of Apache Wayang can speed up spatial jobs. We executed the benchmarks on an HPC cluster with reproducible Spark cluster configurations."}),"\n",(0,n.jsx)("div",{style:{textAlign:"center"},children:(0,n.jsx)("img",{width:"75%",alt:"Spatial benchmark 1",src:"/img/benchmarks/spatial-bench1.png"})}),"\n",(0,n.jsxs)(a.ul,{children:["\n",(0,n.jsxs)(a.li,{children:[(0,n.jsx)(a.strong,{children:"Job 1:"})," Spatial Join of parks (~44k) and lakes (~140k) in Germany with spatial predicate CONTAINS, no index on Postgres tables, Spark cluster with 4 nodes"]}),"\n",(0,n.jsxs)(a.li,{children:[(0,n.jsx)(a.strong,{children:"Job 2:"})," Spatial Join of parks (~44k) and lakes (~140k) in Germany with spatial predicate CONTAINS, spatial index on Postgres tables, Spark cluster with 4 nodes"]}),"\n",(0,n.jsxs)(a.li,{children:[(0,n.jsx)(a.strong,{children:"Job 3:"})," Spatial Join of two synthetic datasets containing boxes (100k and 1M) with spatial predicate INTERSECTS, spatial index on Postgres tables, Spark cluster with 8 nodes"]}),"\n"]}),"\n",(0,n.jsx)(a.p,{children:"The above figure shows that there are use cases in which each of the currently supported platforms performs best. For small datasets, Java performs best if there is no spatial index available for Postgres; otherwise, Postgres outperforms Java. Due to the Spark overhead, Sedona running on a Spark cluster only gains an advantage in jobs with large datasets, as seen in Job 3."}),"\n",(0,n.jsxs)(a.p,{children:["This is also evident in the following figure. While Java and Postgres perform better than Sedona on a Spark cluster for joins on small datasets, this trend reverses for joins of larger datasets. Especially for the join of 100k and 10M boxes (generated using ",(0,n.jsx)(a.a,{href:"https://star.cs.ucr.edu",children:"star.cs.ucr.edu"}),"), the Spark cluster outperforms the single node execution of Java and Postgres. The poor performance of Sedona/Spark on a cluster with only one node indicates that this advantage is actually coming from the distributed workload and not just from using Sedona instead of JTS or PostGIS operators."]}),"\n",(0,n.jsx)("div",{style:{textAlign:"center"},children:(0,n.jsx)("img",{width:"75%",alt:"Spatial benchmark 2",src:"/img/benchmarks/spatial-bench2.png"})}),"\n",(0,n.jsx)(a.p,{children:"The performance gained by using larger cluster configurations can also be seen in the following visualization of runtime results of box joins with datasets of various sizes."}),"\n",(0,n.jsx)("div",{style:{textAlign:"center"},children:(0,n.jsx)("img",{width:"75%",alt:"Spatial benchmark 3",src:"/img/benchmarks/spatial-bench3.png"})}),"\n",(0,n.jsx)(a.p,{children:"Other than dataset size, selectivity and subsequently the join result size can also impact execution time significantly. The following chart shows the execution time of joining synthetic box datasets containing 1M boxes each. For each run, one of the datasets contained boxes with decreasing max edge lengths, resulting in higher selectivity for the intersection join. Execution times for Java decreased significantly with decreasing box edge lengths, while execution times for the Spark platform stayed roughly the same."}),"\n",(0,n.jsx)("div",{style:{textAlign:"center"},children:(0,n.jsx)("img",{width:"75%",alt:"Spatial benchmark 4",src:"/img/benchmarks/spatial-bench4.png"})}),"\n",(0,n.jsx)(a.p,{children:"The benchmark results show multiple scenarios in which platform choice has a significant impact on runtime. Spatial data processing can therefore benefit greatly from using the new spatial operators in Apache Wayang."}),"\n",(0,n.jsx)(a.hr,{}),"\n",(0,n.jsx)(a.h2,{id:"future-work",children:"Future Work"}),"\n",(0,n.jsx)(a.p,{children:"Our spatial extension enables basic spatial workloads using filter and join operations on the Java, Spark, and Postgres platforms. However, additional operators like nearest neighbor or within-distance operations could enable even more complex scenarios."}),"\n",(0,n.jsx)(a.p,{children:"Adding platforms specifically designed for spatial data processing could improve performance even further. An interesting candidate for this could be the relatively recently introduced Apache SedonaDB database engine."}),"\n",(0,n.jsx)(a.p,{children:"Currently, the execution platform has to be chosen manually. Part of potential future work should therefore be the implementation of heuristics for platform selection."})]})}function d(e={}){const{wrapper:a}={...(0,i.R)(),...e.components};return a?(0,n.jsx)(a,{...e,children:(0,n.jsx)(p,{...e})}):p(e)}},8453(e,a,t){t.d(a,{R:()=>r,x:()=>o});var n=t(6540);const i={},s=n.createContext(i);function r(e){const a=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(a):{...a,...e}},[a,e])}function o(e){let a;return a=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:r(e.components),n.createElement(s.Provider,{value:a},e.children)}}}]);